  let orders = inputData.json;
  if (orders === undefined || orders === null || typeof orders !== 'object') {
    orders = [];
  } else if (!Array.isArray(orders)) {
    console.log('Invalid data format, forcing empty array');
    orders = [];
  }
  // Merge webhook data with orders
  const output = {
    orders: orders,
    ...webhookData // Preserve original payload fields
  };
  // Return normalized data
  return [{ json: output }];
} catch (error) {
  console.log('Error in Set Default Order Data: ' + error.message);
  return [{ json: { orders: [] } }];
