const CONFIG = {
    COUPON_PREFIX: '',       // Specify the Coupon Code Phrase here
    EXPIRY_MINUTES: 30,      // Time until expiry
    TIMEZONE: 'UTC'          // CHANGE THIS: 'Asia/Kolkata', 'America/New_York', 'UTC', etc.
};

// --- COUPON GENERATION LOGIC ---
const customerId = $input.first().json.body.arg.customer_id;

// Generate base number (0-1000) based on ID and current timestamp
let baseNumber = Math.floor(Math.abs(parseInt(customerId + Date.now().toString().slice(-6))) % 1000 + 1);
let codeNumber = ('000' + baseNumber).slice(-3);
let finalCode = CONFIG.COUPON_PREFIX + codeNumber;

// Handle collisions
let usedCodes = $json.usedCodes || [];
while (usedCodes.includes(finalCode)) {
    baseNumber = (baseNumber % 1000) + 1;
    codeNumber = ('000' + baseNumber).slice(-3);
    finalCode = CONFIG.COUPON_PREFIX + codeNumber;
}
usedCodes.push(finalCode);

// --- TIME CALCULATION LOGIC ---

// 1. Calculate the exact expiry moment (Current Time + Expiry Minutes)
const now = new Date();
const expiryDate = new Date(now.getTime() + CONFIG.EXPIRY_MINUTES * 60000);

// 2. Format: "HH:mm" (e.g., "19:09") based on TARGET TIMEZONE
const expiryTime = expiryDate.toLocaleTimeString('en-GB', {
    timeZone: CONFIG.TIMEZONE,
    hour12: false,
    hour: '2-digit',
    minute: '2-digit'
});

// 3. Format: "YYYY-MM-DD HH:mm:ss" based on TARGET TIMEZONE
// We use the 'sv-SE' (Swedish) locale hack, which naturally formats dates as ISO 8601 (YYYY-MM-DD)
const dateExpires = expiryDate.toLocaleString('sv-SE', {
    timeZone: CONFIG.TIMEZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
}).replace('T', ' ');

return [{
    json: {
        code: finalCode,
        usedCodes: usedCodes,
        customer_id: customerId,
        expiry_time: expiryTime,   // Local time in HH:mm
        date_expires: dateExpires, // Full timestamp YYYY-MM-DD HH:mm:ss
        timezone: CONFIG.TIMEZONE  // Helpful for debugging
    }
}];

